// When reasoning_effort is set, the model returns content blocks as an array
// (e.g. [{type:'thinking',...},{type:'text',...}]). Strip thinking blocks
// so llm-rubric only sees the final answer text.
if (Array.isArray(output)) {
  return output.filter(b => b.type === 'text').map(b => b.text).join('');
}
return output;
